import React from "react";
export default function FeatureBrand() {
  const list = [
    { image: "/featurebrandsimages/1.png", link: false },
    { image: "/featurebrandsimages/2.png", link: false },
    { image: "/featurebrandsimages/3.png", link: false },
    { image: "/featurebrandsimages/4.png", link: false },
    { image: "/featurebrandsimages/5.png", link: false },
    { image: "/featurebrandsimages/6.png", link: false },
    { image: "/featurebrandsimages/7.png", link: false },
    { image: "/featurebrandsimages/8.png", link: false },
    { image: "/featurebrandsimages/9.png", link: false },
    { image: "/featurebrandsimages/10.png", link: false },
  ];
  return (
    <div className="py-10 px-6 bg-white rounded-4xl shadow-xl ">
      <h1 className="text-xl mb-10 font-bold text-black">FEATURED BRANDS</h1>
      <div className=" ps-5  grid  grid-cols-5 gap-10 items-center ">
        {list.map((item, index) => {
          // console.log(item.image)
          return (
            <img
              key={index}
              src={item.image}
              alt="brand"
            
            />
          );
        })}
      </div>
    </div>
  );
}
